// Universeller HTTP-Aufruf gegen eine REST-API.
async function run(input) {
  const url = String((input && input.url) || '');
  if (!/^https?:\/\//.test(url)) return { fehler: 'Bitte eine vollstaendige http(s)-URL angeben.' };
  const method = String((input && input.method) || 'GET').toUpperCase();
  const headers = (input && input.headers) || {};
  const opts = { method: method, headers: headers };
  if (input && input.body != null && method !== 'GET' && method !== 'HEAD') {
    opts.body = typeof input.body === 'string' ? input.body : JSON.stringify(input.body);
    if (!headers['content-type'] && !headers['Content-Type']) headers['content-type'] = 'application/json';
  }
  const res = await fetch(url, opts);
  const ct = res.headers.get('content-type') || '';
  let data;
  if (ct.indexOf('application/json') >= 0) { try { data = await res.json(); } catch (e) { data = await res.text(); } }
  else { data = await res.text(); if (typeof data === 'string' && data.length > 6000) data = data.slice(0, 6000) + ' [gekuerzt]'; }
  return { status: res.status, ok: res.ok, daten: data };
}
